const cur = msg.payload.current;
const temp      = cur.temperature_2m;
const humidity  = cur.relative_humidity_2m;
const pressure  = cur.pressure_msl;       // hPa niveau mer — identique à OpenWeather
const windSpeed = cur.wind_speed_10m;
const windDir   = cur.wind_direction_10m;

// Stocker dans contexte global pour le keepalive
global.set('outdoor_temp',      temp);
global.set('outdoor_humidity',  humidity);
global.set('outdoor_pressure',  pressure);
global.set('outdoor_wind_speed', windSpeed);
global.set('outdoor_wind_dir',  windDir);

node.status({fill: 'green', shape: 'dot', text: `${temp}°C — ${humidity}% — ${pressure}hPa`});

// Message 1 : capteur température/humidité/pression (instance 20)
const heatMsg = {
    topic:   'santuario/heat/1/venus',
    payload: JSON.stringify({
        Temperature:     temp,
        TemperatureType: 4,
        Humidity:        humidity,
        Pressure:        pressure
    })
};

// Message 2 : capteur météo/irradiance (instance 40)
const meteoMsg = {
    topic:   'santuario/meteo/venus',
    payload: JSON.stringify({
        Irradiance:          0,
        TodaysYield:         0,
        ExternalTemperature: temp,
        WindSpeed:           windSpeed,
        WindDirection:       windDir
    })
};

// Double tableau = 2 messages sur la sortie 1 (pas 2 sorties distinctes)
return [[heatMsg, meteoMsg]];

const temp      = global.get('outdoor_temp');
const humidity  = global.get('outdoor_humidity');
const pressure  = global.get('outdoor_pressure');
const windSpeed = global.get('outdoor_wind_speed');
const windDir   = global.get('outdoor_wind_dir');

// Attendre la première récupération Open-Meteo
if (temp === undefined || temp === null) {
    return null;
}

const heatMsg = {
    topic:   'santuario/heat/1/venus',
    payload: JSON.stringify({
        Temperature:     temp,
        TemperatureType: 4,
        Humidity:        humidity,
        Pressure:        pressure
    })
};

const meteoMsg = {
    topic:   'santuario/meteo/venus',
    payload: JSON.stringify({
        Irradiance:          0,
        TodaysYield:         0,
        ExternalTemperature: temp,
        WindSpeed:           windSpeed,
        WindDirection:       windDir
    })
};

// Double tableau = 2 messages sur la sortie 1
return [[heatMsg, meteoMsg]];
